def verify(answer):
    from sympy import symbols, sympify, limit, oo, simplify, Symbol
    x = Symbol('x')
    try:
        s = str(answer).strip()
        if '=' in s:
            s = s.split('=', 1)[1]
        expr = sympify(s)
        f = (2*x**2 + x - 13) / (2*x - 5)
        diff = simplify(f - expr)
        lim_pos = limit(diff, x, oo)
        lim_neg = limit(diff, x, -oo)
        if lim_pos != 0 or lim_neg != 0:
            return False
        # Ensure it's linear (mx+b form)
        poly = expr.as_poly(x)
        if poly is None:
            return False
        if poly.degree() > 1:
            return False
        return True
    except Exception:
        return False

