def verify(answer):
    # Parse answer - expect a number (possibly multiple separated by commas)
    try:
        parts = [p.strip() for p in str(answer).replace(';', ',').split(',') if p.strip()]
        vals = set()
        for p in parts:
            vals.add(Rational(p))
    except Exception:
        try:
            vals = {Rational(str(answer).strip())}
        except Exception:
            return False

    # Find all possible values of a/b + b/a - ab given ab = a - b, a,b nonzero
    # Parametrize: pick b, solve ab = a - b => a(b-1) = -b => a = -b/(b-1) = b/(1-b)
    # Need b != 1, and a nonzero means b nonzero (given).
    # Compute expression over sample b values
    found = set()
    from sympy import Rational as R
    test_bs = [R(1,2), R(2), R(3), R(-1), R(-2), R(1,3), R(5), R(-3,2), R(7,4)]
    for b in test_bs:
        if b == 0 or b == 1:
            continue
        a = b/(1-b)
        if a == 0:
            continue
        # verify ab = a - b
        if a*b != a - b:
            continue
        expr = a/b + b/a - a*b
        found.add(expr)

    return vals == found

