def verify(answer):
    try:
        s = str(answer).strip()
        # parse list of numbers
        parts = [p.strip() for p in s.replace('[','').replace(']','').split(',')]
        roots = [float(p) for p in parts if p]
    except Exception:
        return False

    def poly(x):
        return x**4 + 2*x**3 - 7*x**2 - 8*x + 12

    # Check each given root satisfies polynomial
    for r in roots:
        if abs(poly(r)) > 1e-6:
            return False

    # Find all real roots by checking integer candidates (rational root theorem: divisors of 12)
    actual_roots = []
    for cand in [-12,-6,-4,-3,-2,-1,1,2,3,4,6,12]:
        if poly(cand) == 0:
            actual_roots.append(cand)

    # Since it's degree 4, check we have all of them
    # Verify by polynomial division that these are all roots
    from sympy import symbols, factor, solve, Poly
    x = symbols('x')
    all_roots = solve(x**4 + 2*x**3 - 7*x**2 - 8*x + 12, x)
    all_roots_f = sorted([float(r) for r in all_roots])

    given_sorted = sorted(roots)
    if len(given_sorted) != len(all_roots_f):
        return False
    for a, b in zip(given_sorted, all_roots_f):
        if abs(a - b) > 1e-6:
            return False
    return True

