        try:
            av = sympify(a.replace('oo', 'oo'))
            bv = sympify(b)
            left_open = (lb == '(')
            right_open = (rb == ')')
            if av == -oo:
                av = S.NegativeInfinity
            if bv == oo:
                bv = S.Infinity
            intervals.append(Interval(av, bv, left_open, right_open))
        except Exception:
            return False

    claimed = Union(*intervals) if len(intervals) > 1 else intervals[0]

