    from itertools import combinations
    # Enumerate all ways to place 2 pebbles in each row such that each column has 2.
    # Row choice: combination of 2 columns out of 6. Use DFS with column counts.
    total = 0
    n = 6
    row_choices = list(combinations(range(n), 2))

    def dfs(row, col_count, pebbles):
        nonlocal total
        if row == n:
            if all(c == 2 for c in col_count):
                # Build union-find on pebbles (cells)
                # Two pebbles same group if same row or same column
                # Group by row: pebbles in same row connected
                # Group by col: pebbles in same col connected
                parent = list(range(len(pebbles)))
                def find(x):
                    while parent[x] != x:
                        parent[x] = parent[parent[x]]
                        x = parent[x]
                    return x
                def union(a, b):
                    ra, rb = find(a), find(b)
                    if ra != rb:
                        parent[ra] = rb
                # group by row
                rows = {}
                cols = {}
                for i, (r, c) in enumerate(pebbles):
                    rows.setdefault(r, []).append(i)
                    cols.setdefault(c, []).append(i)
                for lst in list(rows.values()) + list(cols.values()):
                    for i in range(1, len(lst)):
                        union(lst[0], lst[i])
                groups = len(set(find(i) for i in range(len(pebbles))))
                total += 2 ** groups
            return
        for (c1, c2) in row_choices:
            if col_count[c1] < 2 and col_count[c2] < 2:
                col_count[c1] += 1
                col_count[c2] += 1
                pebbles.append((row, c1))
                pebbles.append((row, c2))
                dfs(row + 1, col_count, pebbles)
                pebbles.pop()
                pebbles.pop()
                col_count[c1] -= 1
                col_count[c2] -= 1

