                if abs(f(zm)) < abs(f(complex(math.cos(lo),math.sin(lo)))):
                    if abs(f(complex(math.cos(lo),math.sin(lo)))) < abs(f(complex(math.cos(hi),math.sin(hi)))):
                        hi = mid
                    else:
                        lo = mid
                else:
                    hi = mid if abs(f(complex(math.cos(hi),math.sin(hi)))) > abs(f(complex(math.cos(lo),math.sin(lo)))) else lo
            zm = complex(math.cos((lo+hi)/2), math.sin((lo+hi)/2))
            if abs(f(zm)) < 1e-6:
                th = (lo+hi)/2
                # dedupe
                is_new = True
                for ex in thetas_found:
                    if abs(ex - th) < 1e-4 or abs(ex - th - 2*math.pi) < 1e-4:
                        is_new = False
                        break
                if is_new:
                    thetas_found.append(th)
        prev_theta = t
        prev_val = val
    # Keep only those in [0, pi)
    valid = [t for t in thetas_found if 0 <= t < math.pi - 1e-6]
    total = sum(valid)
    try:
        ans = float(str(answer).strip().replace('pi', str(math.pi)))
    except Exception:
        try:
            from sympy import sympify
            ans = float(sympify(str(answer)))
        except Exception:
            return False
    return abs(ans - total) < 1e-3

