def verify(answer):
    # Enumerate all tilings of 4x6 rectangle by L-triominoes, then for each
    # tiling count proper 3-colorings of the adjacency graph.
    # 4*6 = 24 cells, 24/3 = 8 triominoes.

    W, H = 6, 4
    cells = [(x,y) for y in range(H) for x in range(W)]

    # All L-triomino shapes (2x2 missing one corner), 4 orientations
    shapes = []
    for missing in range(4):
        cs = []
        for i in range(2):
            for j in range(2):
                if i*2+j != missing:
                    cs.append((j,i))
        shapes.append(cs)

    # For each cell, find all triominoes containing it (as canonical sorted tuples)
    # We'll do recursion: find first empty cell, try all triominoes covering it.

    def place_options(filled, x, y):
        opts = []
        for shape in shapes:
            # try placing shape such that (x,y) is one of its cells
            for ax,ay in shape:
                tri = []
                ok = True
                for dx,dy in shape:
                    nx, ny = x + dx - ax, y + dy - ay
                    if not (0 <= nx < W and 0 <= ny < H):
                        ok = False; break
                    if (nx,ny) in filled:
                        ok = False; break
                    tri.append((nx,ny))
                if ok:
                    opts.append(tuple(sorted(tri)))
        return list(set(opts))

    total = 0

    def chromatic_3(adj, n):
        # count proper 3-colorings
        colors = [-1]*n
        def rec(i):
            if i == n:
                return 1
            s = 0
            for c in range(3):
                ok = True
                for j in adj[i]:
                    if j < i and colors[j] == c:
                        ok = False; break
                if ok:
                    colors[i] = c
                    s += rec(i+1)
                    colors[i] = -1
            return s
        return rec(0)

    def share_edge(t1, t2):
        s1 = set(t1); s2 = set(t2)
        for (x,y) in s1:
            for (dx,dy) in [(1,0),(-1,0),(0,1),(0,-1)]:
                if (x+dx, y+dy) in s2:
                    return True
        return False

    def search(filled, tris):
        nonlocal total
        if len(filled) == W*H:
            n = len(tris)
            adj = [[] for _ in range(n)]
            for i in range(n):
                for j in range(i+1,n):
                    if share_edge(tris[i], tris[j]):
                        adj[i].append(j); adj[j].append(i)
            total += chromatic_3(adj, n)
            return
        # find first empty cell
        for y in range(H):
            for x in range(W):
                if (x,y) not in filled:
                    for opt in place_options(filled, x, y):
                        newf = filled | set(opt)
                        search(newf, tris + [opt])
                    return

    search(set(), [])

    try:
        return int(str(answer).strip()) == total
    except Exception:
        return False

def verify(answer):
    from itertools import product
    # Enumerate all strings of length 15 with five 1s, five 2s, five 3s
    # with no two adjacent characters the same, then check deletability

    # Generate all such strings via recursion
    valid_strings = []
    def gen(s, c1, c2, c3):
        if len(s) == 15:
            if c1 == 5 and c2 == 5 and c3 == 5:
                valid_strings.append(s)
            return
        last = s[-1] if s else None
        if c1 < 5 and last != '1':
            gen(s + '1', c1+1, c2, c3)
        if c2 < 5 and last != '2':
            gen(s + '2', c1, c2+1, c3)
        if c3 < 5 and last != '3':
            gen(s + '3', c1, c2, c3+1)
    gen('', 0, 0, 0)

    # For each string, check if it can be reduced to empty
    # via removals of "123", "231", "312"
    patterns = ['123', '231', '312']
    memo = {}
    def can_delete(s):
        if s in memo:
            return memo[s]
        if s == '':
            return True
        result = False
        for i in range(len(s) - 2):
            if s[i:i+3] in patterns:
                if can_delete(s[:i] + s[i+3:]):
                    result = True
                    break
        memo[s] = result
        return result

    count = 0
    for s in valid_strings:
        if can_delete(s):
            count += 1

    try:
        return int(str(answer).strip()) == count
    except Exception:
        return False
